const translations={en:{"desktop-only":"Desktop Only","desktop-warning":"Label Labor is currently only available on desktop/laptop.<br>If using a computer, please increase the window size!",about:"About us","nav-login":"Login","nav-what-is":"What is it?","what-is":"What is Label Labor?","demo-labels":"Demo Shelf Labels","contact-request":"Request a Quote","back-login":"← Back to Login",login:"Login",username:"Username",password:"Password","all-labels":"All generated shelf labels: ","demo-video":"Tutorial Video","user-guide":"User Guide","step1-title":"Login","step1-desc":"Log in on the main page using the username and password you received.","step2-title":"Download the Excel template","step2-desc":'Click the "Download Template Excel" button, then open the file.',"step3-title":"Filling out the template","step3-desc":'Paste your data into the <span style="color: red;">red-marked</span> columns (up to approx. 400 rows). Please pay attention to the following:<br><br><ul><li>Make sure there are no empty or unnecessary rows, and no extra spaces.</li><li>The "Pack_size" field format should be: quantity + space + unit (e.g. "1 kg", "400 ml").</li><li>For items sold individually, the correct format is simply: "pcs".</li><li>In the "Price" field, enter only the number (e.g. "19").</li></ul>',"step4-title":"Upload Excel file","step4-desc":'Click the "Upload Excel File (.xlsx)" button and select your completed template.',"step5-title":"Data validation and correction","step5-desc":'For consistent labels, the system automatically corrects minor errors — just confirm them with the checkmark icon. If needed, you can also edit the data manually.<br><br><div style="display:flex;flex-direction:column;gap:8px;margin-bottom:14px;"><div><span style="display:inline-block;width:14px;height:14px;background:#4caf50;border-radius:3px;vertical-align:middle;margin-right:6px;"></span> <strong>Green</strong> background — field marked as ready</div><div><span style="display:inline-flex;align-items:center;justify-content:center;background:#4caf50;color:#fff;border-radius:4px;width:20px;height:20px;font-size:12px;vertical-align:middle;margin-right:4px;">✓</span> Use the checkmark icon to confirm and mark as ready</div></div><strong>By the end of validation, all fields should have a green background.</strong>',"step6-title":"Check shelf labels and select shelf label type","step6-desc":"Review the information displayed on the shelf labels, then select the appropriate shelf label type.","step7-title":"Modify shelf label data (if needed)","step7-desc":'Click the "View Data" button to open a table with all shelf label data. If necessary, you can edit any field. Click "Save and Generate" to regenerate the shelf labels with the updated changes.',"step8-title":"Download and print shelf labels","step8-desc":'Click the "Download PDF" button. If you want to generate new shelf labels, refresh the page before starting the process. You can print the downloaded labels.pdf document with any standard printer — just like any invoice or regular document.',"contact-footer-pre":"Contact: ","footer-analytics":"Anonymous visit tracking: Cloudflare Analytics",contact:"Contact us","about-title":"Welcome to Label Labor!","about-intro":"In most of the stores, creating uniform shelf labels quickly and efficiently can be a real challenge.<br>Label Labor provides an easy solution: generate and print shelf labels directly from a simple Excel spreadsheet.","about-benefits-title":"Benefits of using Label Labor:","about-benefit-1":"Hundreds of shelf labels in just minutes","about-benefit-2":"Saving time and money on shelf label creation","about-benefit-3":"Shelf labels that can be printed on regular A4 paper — no need to buy expensive roll labels","about-benefit-4":"Printing shelf labels even with a regular printer for invoices — no special roll label printer required","about-benefit-5":"Personalized shelf label formats","about-benefit-6":"Online support for introduction and usage","contact-form-title":"Request a Personalized Quote!","contact-name":"Full Name","contact-email":"Email Address","contact-company":"Company Name","contact-message":"Message","contact-submit":"Send Request","contact-success":"Your request has been sent successfully!","contact-error":"An error occurred while sending the quote request. Please try again.","login-success":"Login successful! Redirecting...","login-error":"Invalid username or password!","contact-subtitle-1":"Pricing and Information","contact-text-1":"Custom-designed interface and shelf label format for your company, with training included. Additional shelf label formats can be provided upon request.","contact-text-2":"Afterwards, a monthly fee covers maintenance, bug fixes, and implementation of small modification requests.","contact-subtitle-2":"Helpful Information for us","contact-text-3":'Please provide the following information in the "Message" field:',"contact-benefit-1":"How many different shelf label sizes would you like to generate on the page","contact-benefit-2":"Within a given shelf label size, how many different shelf label layouts would you like to use","contact-benefit-3":"Number of logos you want to use on the various shelf labels","contact-benefit-4":"Number of stores where you will use Label Labor","form-location-hint":"The quote request form can be found at the bottom of the page. Please fill it out according to the instructions provided.","scroll-to-form":"Go to Form","hero-title":"Professional <span>shelf labels</span><br>in minutes","hero-total-label":"shelf labels generated","hero-badge-label":"shelf labels in minutes","hero-stat-pre":"Already ","hero-stat-suf":" shelf labels generated","cta-quote-btn":"Request a Quote","cta-examples-btn":"View Examples","why-label":"Why Label Labor?",kifejezetten:"Designed specifically for paint store owners and retail workers.","card-fast-title":"Fast","card-fast-desc":"Upload your spreadsheet and get 100+ printable shelf labels in seconds.","card-cheap-title":"Affordable","card-cheap-desc":"Prints on standard A4 paper — no expensive specialty shelf labels needed.","card-printer-title":"Any Printer","card-printer-desc":"Works with any home or office printer. Instantly, without setup.","card-brand-title":"Your Brand","card-brand-desc":"Shelf labels appear with your company logo and custom formatting.","card-barcode-title":"Barcodes","card-barcode-desc":"Automatic barcode generation in formats compatible with your POS system.","card-support-title":"Support","card-support-desc":"If something doesn't work, live chat and email support is available.","howto-label":"How does it work?","howto-title":"3 steps to your first print","howto-lead":"No installation needed, no registration required to try.","howto1-title":"Log in","howto1-desc":"Enter your credentials — takes 10 seconds.","howto2-title":"Upload Excel","howto2-desc":"Drop in your existing spreadsheet, or fill in the template.","howto3-title":"Print","howto3-desc":'Click "Generate", then print directly from your browser.',"pricing-title":"Monthly fee","pricing-desc":"Unlimited printing, updates and online support.","pricing-amount":"<small>from</small> 9 900 HUF <small>/ month</small>","pricing-cta":"Request a Quote","examples-eyebrow":'Sample output <span class="new-text-badge">NEW</span>',"examples-heading":"Here's what the result looks like","examples-lead":"Custom shelf labels, printed on A4 paper, cut and placed in the shelf rail.","examples-caption-1":"Full print page — this is how the final PDF looks","examples-caption-2":"A single shelf label up close","examples-download":"Download PDF"},hu:{"desktop-only":"Desktop Only","desktop-warning":"A Label Labor jelenleg csak asztali számítógépen/laptopon érhető el.<br>Ha számítógépen használja, növelje az ablak méretét!",about:"Bemutatkozás","nav-login":"Bejelentkezés","nav-what-is":"Mi ez?","what-is":"Mi az a Label Labor?","demo-labels":"Példa polccímkék","contact-request":"Árajánlat","back-login":"← Vissza a bejelentkezéshez",login:"Bejelentkezés",username:"Felhasználónév",password:"Jelszó","all-labels":"Összes generált polccímke: ","demo-video":"Bemutató videó","user-guide":"Használati útmutató","step1-title":"Bejelentkezés","step1-desc":"Lépjen be a főoldalon a kapott felhasználónévvel és jelszóval.","step2-title":"Sablon excel letöltése","step2-desc":'Kattintson a "Sablon Excel letöltése" gombra, majd nyissa meg a fájlt.',"step3-title":"A sablon excel kitöltése","step3-desc":'A <span style="color: red;">pirossal jelölt</span> oszlopokba másolja be a saját adatait (legfeljebb kb. 400 sor). Ügyeljen az alábbiakra:<br><br><ul><li>Ne maradjanak üres vagy felesleges sorok, illetve szóközök.</li><li>A "Kiszerelés" mező formátuma: mennyiség + szóköz + mértékegység (pl. "1 kg", "400 ml").</li><li>Darabos termék esetén a helyes formátum: "db".</li><li>Az "Ár" mezőbe csak a számot írja (pl. "999"), a "Ft" megjelölést nem kell hozzáadni.</li></ul>',"step4-title":"Excel fájl feltöltése","step4-desc":'Kattintson az "Excel fájl feltöltése (.xlsx)" gombra, és válassza ki a kitöltött sablont.',"step5-title":"Adatok ellenőrzése, javítása","step5-desc":'Az egységes polccímkék érdekében a kisebb hibákat a rendszer kijavítja, csak a pipa ikonnal kell jóváhagyni. Ha szükséges, manuálisan is lehet módosítani az adatokat.<br><br><div style="display:flex;flex-direction:column;gap:8px;margin-bottom:14px;"><div><span style="display:inline-block;width:14px;height:14px;background:#4caf50;border-radius:3px;vertical-align:middle;margin-right:6px;"></span> <strong>Zöld</strong> háttér — mező késznek jelölve</div><div><span style="display:inline-flex;align-items:center;justify-content:center;background:#4caf50;color:#fff;border-radius:4px;width:20px;height:20px;font-size:12px;vertical-align:middle;margin-right:4px;">✓</span> Pipa ikonnal lehet jóváhagyni és késznek jelölni</div></div><strong>Az adatellenőrzés legvégén az összes mező háttere legyen zöld.</strong>',"step6-title":"Polcpolccímkék ellenőrzése és polccímke-típus választása","step6-desc":"Ellenőrizze a polccímkéken megjelenő adatokat, majd válassza ki a megfelelő polccímke-típust.","step7-title":"Polcpolccímke-adatok módosítása (ha szükséges)","step7-desc":'Az "Adatok megtekintése" gombra kattintva megjelenik egy táblázat, benne az összes polccímke-adattal. Ha szükséges, lehet módosítani bármelyik adatot, a "Mentés és generálás" gombra kattintva pedig a rendszer ismét elkészíti a polccímkéket a friss változtatásokkal.',"step8-title":"Polcpolccímkék letöltése és nyomtatása","step8-desc":'Kattintson a "PDF letöltése" gombra. Ha új polccímkéket szeretne generálni, frissítsen rá az oldalra a folyamat megkezdése előtt. A letöltött cimkek.pdf dokumentumot bármilyen hagyományos nyomtatóval kinyomtathatja – ugyanúgy, mint egy számlát vagy más dokumentumot.',"contact-footer-pre":"Kapcsolat: ","footer-analytics":"Anonim látogatottsági mérés: Cloudflare Analytics",contact:"Kapcsolat","about-title":"Üdvözöllek a Label Labor oldalán!","about-intro":"A legtöbb boltban problémát jelent a polcsínbe való címkék gyors, költséghatékony és egységes előállítása.<br>A Label Labor erre kínál egyszerű megoldást: néhány kattintással készíthet és nyomtathat polccímkéket egyszerű Excel táblázatból.","about-benefits-title":"A Label Labor használatának előnyei:","about-benefit-1":"Több 100 polccímke percek alatt","about-benefit-2":"Időt és pénzt tud spórolni a polccímkék előállításán","about-benefit-3":"Hagyományos A4-es lapra is nyomtatható polccímkék, nem kell a drága öntapadós, tekercses polccímkét vásárolni","about-benefit-4":"Egyszerű számlanyomtatásra használt nyomtatóval is lehet polccímkét nyomtatni, nem szükséges a speciális, tekercses címkenyomtató","about-benefit-5":"Egyedi, személyre szabott polccímke-formátum","about-benefit-6":"Online támogatás a bevezetés és használat során","contact-form-title":"Kérjen személyre szabott árajánlatot!","contact-name":"Név","contact-email":"Email cím","contact-company":"Cég neve","contact-message":"Üzenet","contact-submit":"Küldés","contact-success":"Árajánlat sikeresen elküldve!","contact-error":"Hiba történt az árajánlat küldésekor. Kérjük, próbálja újra.","login-success":"Sikeres bejelentkezés! Átirányítás...","login-error":"Hibás felhasználónév vagy jelszó!","contact-subtitle-1":"Árképzés és információk","contact-text-1":"A cégének egyedileg elkészített felület és polccímke-formátum, betanítás. Több polccímke-formátum kérés esetén.","contact-text-2":"Ezt követően havi díj ellenében biztosítjuk a karbantartást, hibajavítást és kisebb módosítási kérések teljesítését.","contact-subtitle-2":"Nekünk hasznos információk","contact-text-3":'Kérjük adja meg az alábbi információkat az "Üzenet" mezőbe:',"contact-benefit-1":"Hány féle méretű polccímkét szeretne generálni az oldalon","contact-benefit-2":"Egy adott polccímke-méreten belül hány féle elrendezésű polccímkét szeretne használni","contact-benefit-3":"Felhasználni kívánt logók mennyisége a különböző polccímkéken","contact-benefit-4":"Boltjainak száma, ahol használná a Label Labort","form-location-hint":"Az űrlap az oldal alján található. Kérjük, megadott útmutató alapján töltse ki.","scroll-to-form":"Ugrás az űrlaphoz","hero-title":"Professzionális <span>polccímkék</span><br>percek alatt","hero-total-label":"összes generált polccímke","hero-badge-label":"polccimke percek alatt","hero-stat-pre":"Eddig ","hero-stat-suf":" polccimkét generáltak","cta-quote-btn":"Ajánlatot kérek","cta-examples-btn":"Példa polccímkék","why-label":"Miért Label Labor?",kifejezetten:"Kifejezetten festékbolt-tulajdonosoknak és kiskereskedelmi dolgozóknak terveztük.","card-fast-title":"Gyors","card-fast-desc":"Töltse fel Excel-táblázatát és 100+ nyomtatható polccímkét kap másodpercek alatt.","card-cheap-title":"Olcsó","card-cheap-desc":"Hagyományos A4-es papírra nyomtat – nincs szükség drága, speciális nyomtatóra vagy papírra.","card-printer-title":"Bármilyen nyomtató","card-printer-desc":"Minden otthoni és irodai nyomtatóval működik. Azonnal, beállítás nélkül.","card-brand-title":"Saját arculat","card-brand-desc":"A cég logójával és saját formázással jelennek meg a polccímkék.","card-barcode-title":"Vonalkód","card-barcode-desc":"Automatikus vonalkód-generálás, kasszával is kompatibilis formátumban.","card-support-title":"Segítség kérésre","card-support-desc":"Ha valami nem megy, élő chat és e-mail támogatás áll rendelkezésre.","howto-label":"Hogyan működik?","howto-title":"3 lépés az első nyomtatásig","howto-lead":"Nem kell semmit telepíteni, regisztrálni sem szükséges a kipróbáláshoz.","howto1-title":"Bejelentkezés","howto1-desc":"Adja meg a hozzáférési adatait – ez 10 másodperc.","howto2-title":"Excel feltöltése","howto2-desc":"Húzza be a meglévő Excel-táblázatát, vagy töltse ki a sablont.","howto3-title":"Nyomtatás","howto3-desc":'Kattintson a „Generál" gombra, majd nyomtassa ki közvetlenül a böngészőből.',"pricing-title":"Havi díj","pricing-desc":"Korlátlan nyomtatás, frissítések és online támogatás.","pricing-amount":"9 900 Ft <small>/ hónap-tól</small>","pricing-cta":"Ajánlatot kérek","examples-eyebrow":'Példa kimenet <span class="new-text-badge">ÚJ</span>',"examples-heading":"Így néz ki a végeredmény","examples-lead":"Egyedi polccímkék, amelyek A4-es papírra nyomtatás után kivágva kerülnek a polcsínbe.","examples-caption-1":"Teljes nyomtatási oldal – így néz ki a kész PDF","examples-caption-2":"Egyetlen polccímke közelről","examples-download":"PDF letöltése"}};let currentLang=localStorage.getItem("language")||"hu";function changeLanguage(e){currentLang=e,localStorage.setItem("language",e),document.querySelectorAll("[data-lang]").forEach(t=>{const a=t.getAttribute("data-lang");if(translations[e][a])if("INPUT"===t.tagName||"TEXTAREA"===t.tagName)t.placeholder=translations[e][a];else if("all-labels"===a){const l=t.querySelector(".stats-number");if(l){const s=l.textContent,n=document.createElement("div");n.innerHTML=translations[e][a];const o=n.textContent;"undefined"!=typeof isCounterAnimating&&isCounterAnimating?t.childNodes.forEach(e=>{e.nodeType===Node.TEXT_NODE&&(e.textContent=o)}):t.innerHTML=translations[e][a]+'<span class="stats-number" id="totalLabelCount">'+s+"</span>"}else t.innerHTML=translations[e][a]}else t.innerHTML=translations[e][a]}),document.querySelectorAll(".lang-btn").forEach(t=>{t.classList.remove("active"),t.getAttribute("data-lang-code")===e&&t.classList.add("active")}),document.documentElement.lang=e}document.addEventListener("DOMContentLoaded",()=>{changeLanguage(currentLang),document.querySelectorAll(".lang-btn").forEach(e=>{e.addEventListener("click",()=>{changeLanguage(e.getAttribute("data-lang-code"))})})});